mapper.insert:
insert into books (title, author, publisher, version, price, `condition`,trade_method, location,notes,status,create_time,update_time) VALUES

    (#{book.title},#{book.author},#{book.publisher},#{book.version}
    ,#{book.price},#{book.condition},#{book.tradeMethod},#{book.location}
    ,#{book.notes},#{book.status},#{book.createTime},#{book.updateTime})
